changeSet.sql:
DO $$ BEGIN
CREATE TYPE book_status AS ENUM ('IN_STOCK', 'OUT_OF_STOCK');
EXCEPTION
WHEN duplicate_object THEN null;
END $$;

DO $$ BEGIN
CREATE TYPE order_status AS ENUM ('NEW', 'IN_PROCESS', 'PARTIALLY_COMPLETED', 'COMPLETED', 'CANCELLED');
EXCEPTION
WHEN duplicate_object THEN null;
END $$;

DO $$ BEGIN
CREATE TYPE order_item_status AS ENUM ('NEW', 'PENDING', 'COMPLETED', 'CANCELLED');
EXCEPTION
WHEN duplicate_object THEN null;
END $$;

rollback.sql:
DROP TYPE IF EXISTS order_item_status;
DROP TYPE IF EXISTS order_status;
DROP TYPE IF EXISTS book_status;
